        Map<String, Map<String, Double>> graph = new HashMap<>();
        for (int i = 0; i < equations.size(); i++) {
            String u = equations.get(i).get(0);
            String v = equations.get(i).get(1);
            graph.computeIfAbsent(u, k -> new HashMap<>()).put(v, values[i]);
            graph.computeIfAbsent(v, k -> new HashMap<>()).put(u, 1.0 / values[i]);
        }
        double[] res = new double[queries.size()];
        for (int i = 0; i < queries.size(); i++) {
            res[i] = dfs(graph, queries.get(i).get(0), queries.get(i).get(1), 1.0, new HashSet<>());
        }
        return res;
    }
    private double dfs(Map<String, Map<String, Double>> graph, String curr, String target, double acc, Set<String> seen) {
        if (!graph.containsKey(curr)) return -1.0;
        if (curr.equals(target)) return acc;
        seen.add(curr);
        for (var entry : graph.get(curr).entrySet()) {
            if (seen.contains(entry.getKey())) continue;
            double result = dfs(graph, entry.getKey(), target, acc * entry.getValue(), seen);
            if (result != -1.0) return result;
        }
        return -1.0;
    }
}

class Solution {
    public double[] calcEquation(List<List<String>> equations, double[] values, List<List<String>> queries) {
        Map<String, Map<String, Double>> graph = new HashMap<>();
        for (int i = 0; i < equations.size(); i++) {
            String u = equations.get(i).get(0);
            String v = equations.get(i).get(1);
            graph.computeIfAbsent(u, k -> new HashMap<>()).put(v, values[i]);
            graph.computeIfAbsent(v, k -> new HashMap<>()).put(u, 1.0 / values[i]);
        }
        double[] res = new double[queries.size()];
        for (int i = 0; i < queries.size(); i++) {
            String start = queries.get(i).get(0);
            String end = queries.get(i).get(1);
            if (!graph.containsKey(start) || !graph.containsKey(end)) {
                res[i] = -1.0;
                continue;
            }
            Queue<double[]> queue = new LinkedList<>();
            Set<String> visited = new HashSet<>();
            queue.add(new double[]{graph.get(start).getOrDefault(end, -1.0), 0}); // wait, wrong
            // Actually, need to queue nodes with product
            queue.add(new double[]{0, 1.0}); // index in some way, but since strings, use pair
            // Better to use a class or array with string
            // For simplicity, assume DFS is fine, but to implement BFS:
            Queue<String> q = new LinkedList<>();
            Map<String, Double> prod = new HashMap<>();
            q.add(start);
            prod.put(start, 1.0);
            visited.add(start);
            boolean found = false;
            while (!q.isEmpty()) {
                String curr = q.poll();
                if (curr.equals(end)) {
                    res[i] = prod.get(curr);
                    found = true;
                    break;
                }
                for (var entry : graph.get(curr).entrySet()) {
                    String nei = entry.getKey();
                    if (!visited.contains(nei)) {
                        visited.add(nei);
                        prod.put(nei, prod.get(curr) * entry.getValue());
                        q.add(nei);
                    }
                }
            }
            if (!found) res[i] = -1.0;
        }
        return res;
    }
}
